package main

import (
	"fmt"
	"sync"
)

type Account struct {
	Balance float64 `json:"balance"`
}

var accounts = make(map[string]Account)
var mu sync.Mutex

func getBalance(account string) (float64, error) {
	mu.Lock()
	defer mu.Unlock()

	if balance, ok := accounts[account]; ok {
		return balance.Balance, nil
	}
	return 0, fmt.Errorf("account not found")
}

func updateBalance(account string, amount float64) error {
	mu.Lock()
	defer mu.Unlock()

	if _, ok := accounts[account]; !ok {
		accounts[account] = Account{amount}
	} else {
		accounts[account].Balance += amount
	}
	return nil
}

func deposit(account string, amount float64) error {
	balance, err := getBalance(account)
	if err != nil {
		return err
	}
	updateBalance(account, balance+amount)
	return nil
}

func withdraw(account string, amount float64) error {
	balance, err := getBalance(account)
	if err != nil {
		return err
	}
	if balance < amount {
		return fmt.Errorf("insufficient funds")
	}
	updateBalance(account, balance-amount)
	return nil
}

func main() {
	go func() {
		deposit("12345", 100.0)
		fmt.Println(getBalance("12345"))
	}()

	go func() {
		withdraw("12345", 50.0)
		fmt.Println(getBalance("12345"))
	}()

	select {}
}